        pystray.MenuItem("Open config", lambda *_: actions.open_path(config_path)),
        pystray.Menu.SEPARATOR,
        pystray.MenuItem("Stop service", lambda *_: supervisor.stop_service()),
        pystray.MenuItem("Restart service", lambda *_: supervisor.restart_service()),
        pystray.Menu.SEPARATOR,
