def _start_ws_thread(
    state: TrayState, *, host: str, port: int, stop_event: threading.Event
) -> threading.Thread:
    def _runner() -> None:
        loop = asyncio.new_event_loop()
        asyncio.set_event_loop(loop)
        async_stop = asyncio.Event()

